create table if not exists ac_training_cohorts (id uuid primary key default uuid_generate_v4(), code text unique, name text, service_line text, trainer_id uuid, start_date date, readiness int default 0, attendance int default 0, simulation_score int default 0, certification_rate int default 0, field_validation int default 0, blockers text[] default '{}');
create table if not exists ac_training_modules (id uuid primary key default uuid_generate_v4(), cohort_id uuid references ac_training_cohorts(id), title text, category text, pass_threshold int default 80, mandatory boolean default true, sequence int default 1);
create table if not exists ac_certifications (id uuid primary key default uuid_generate_v4(), person_id uuid references ac_people(id), code text, level text, service_line text, issued_at timestamptz default now(), expires_at timestamptz, status text default 'active', generated_reference text unique);
create table if not exists ac_simulation_scores (id uuid primary key default uuid_generate_v4(), person_id uuid references ac_people(id), module_id uuid references ac_training_modules(id), scenario text, score int, evaluator text, notes text, created_at timestamptz default now());
